import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple


def decode_jwt(
    token: str,
    secret: Optional[str] = None,
    verify: bool = False,
    algorithms: Optional[list] = None
) -> Tuple[Dict[str, Any], Dict[str, Any], bool]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify the signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (header, payload, is_valid)
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS512', 'RS256', 'RS512', 'ES256', 'ES512']
    
    header = {}
    payload = {}
    is_valid = False
    
    try:
        # Decode without verification first to inspect contents
        header = jwt.get_unverified_header(token)
        payload = jwt.decode(token, options={"verify_signature": False})
        
        # If verification is requested and secret is provided
        if verify and secret:
            try:
                verified_payload = jwt.decode(
                    token,
                    secret,
                    algorithms=algorithms
                )
                is_valid = True
                payload = verified_payload
            except jwt.InvalidSignatureError:
                is_valid = False
            except jwt.ExpiredSignatureError:
                is_valid = False
            except jwt.InvalidTokenError:
                is_valid = False
        elif not verify:
            is_valid = None  # Not verified, so validity is unknown
            
    except Exception as e:
        print(f"Error decoding token: {str(e)}")
        
    return header, payload, is_valid


def inspect_jwt(
    token: str,
    secret: Optional[str] = None,
    verify: bool = False,
    pretty_print: bool = True
) -> Dict[str, Any]:
    """
    Inspect a JWT token and return detailed information.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify the signature
        pretty_print: Whether to print formatted output
    
    Returns:
        Dictionary containing token information
    """
    header, payload, is_valid = decode_jwt(token, secret, verify)
    
    result = {
        'header': header,
        'payload': payload,
        'is_valid': is_valid,
        'token_info': {}
    }
    
    # Extract common claims
    if payload:
        result['token_info']['issued_at'] = None
        result['token_info']['expires_at'] = None
        result['token_info']['not_before'] = None
        result['token_info']['is_expired'] = None
        result['token_info']['time_until_expiry'] = None
        
        if 'iat' in payload:
            result['token_info']['issued_at'] = datetime.fromtimestamp(payload['iat']).isoformat()
        
        if 'exp' in payload:
            exp_time = datetime.fromtimestamp(payload['exp'])
            result['token_info']['expires_at'] = exp_time.isoformat()
            result['token_info']['is_expired'] = datetime.now() > exp_time
            
            if not result['token_info']['is_expired']:
                time_diff = exp_time - datetime.now()
                result['token_info']['time_until_expiry'] = str(time_diff)
        
        if 'nbf' in payload:
            result['token_info']['not_before'] = datetime.fromtimestamp(payload['nbf']).isoformat()
        
        if 'sub' in payload:
            result['token_info']['subject'] = payload['sub']
        
        if 'iss' in payload:
            result['token_info']['issuer'] = payload['iss']
        
        if 'aud' in payload:
            result['token_info']['audience'] = payload['aud']
    
    if pretty_print:
        print("=" * 60)
        print("JWT TOKEN INSPECTION")
        print("=" * 60)
        print(f"\nHEADER:")
        print(json.dumps(header, indent=2))
        print(f"\nPAYLOAD:")
        print(json.dumps(payload, indent=2))
        print(f"\nTOKEN INFO:")
        print(json.dumps(result['token_info'], indent=2, default=str))
        print(f"\nVALIDATION:")
        if is_valid is None:
            print("  Status: NOT VERIFIED (signature check skipped)")
        elif is_valid:
            print("  Status: VALID ✓")
        else:
            print("  Status: INVALID ✗")
        print("=" * 60)
    
    return result


def quick_decode(token: str) -> None:
    """Quick decode and print JWT token contents without verification."""
    inspect_jwt(token, verify=False, pretty_print=True)


def verify_jwt_token(token: str, secret: str, algorithms: Optional[list] = None) -> bool:
    """
    Verify a JWT token and return True if valid, False otherwise.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification
        algorithms: List of allowed algorithms
    
    Returns:
        True if token is valid, False otherwise
    """
    _, _, is_valid = decode_jwt(token, secret, verify=True, algorithms=algorithms)
    return is_valid if is_valid is not None else False


